import{FIX_FLAGS}from"../constants.js";const getOpeningBracketIndex=t=>{let e=-1,n=t.length-1;for(;n>=0;){const r=t[n];if("{"===r){e=n;break}if(!/\s/.test(r)&&","!==r){if("type"===t.substring(n-3,n+1)){n-=4;continue}break}n--}return e};export const removeExport=({text:t,start:e,end:n,flags:r})=>{const s=t.substring(0,e),i=t.substring(n);if(r%FIX_FLAGS.NONE)return s+i;const o=t.substring(e,n).trim();if("export"===o||"export default"===o)return s+i;let f=-1,g=-1;if(r&FIX_FLAGS.OBJECT_BINDING){let t=0;for(;t<=i.length;){const e=i[t];if(","===e)g=t+1;else if(r&FIX_FLAGS.WITH_NEWLINE&&("\n"===e||"\r"===e||"\r\n"===e))g=t+1;else{if("}"===e){f=t+1,r&FIX_FLAGS.WITH_NEWLINE&&(g=t);break}if(!/\s/.test(e)){r&FIX_FLAGS.WITH_NEWLINE&&(g=t);break}}t++}}if(r&FIX_FLAGS.EMPTY_DECLARATION&&-1!==f){const t=getOpeningBracketIndex(s);if(-1!==f&&-1!==t){const e=s.substring(0,t).trim(),n=e.endsWith("export")?6:e.endsWith("export type")?11:0,r=e.length-n;if(n){if(i.substring(f).trim().startsWith("from")){const t=i.match(/['"][^'"]+['"]/);if(t?.index){const n=t.index+t[0].length;return e.substring(0,r)+i.substring(n)}}return e.substring(0,r)+i.substring(f)}}}return s+(-1===g?i:i.substring(g))};